import React, { useState } from 'react';
import axios from 'axios';

const BookingForm = () => {
  const [formData, setFormData] = useState({ name: '', email: '', date: '', zone: '' });
  const [loading, setLoading] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('http://localhost:8080/bookings', formData);
      setSuccessMessage('🎉 Booking submitted! Redirecting to payment...');
      
      // Reset form
      setFormData({ name: '', email: '', date: '', zone: '' });
      
      // Razorpay integration
      const options = {
        key: 'YOUR_RAZORPAY_KEY', // Get from Razorpay dashboard
        amount: 50000, // e.g., 500 INR * 100
        currency: 'INR',
        name: 'Ranthambhore Safari',
        description: 'Safari Booking',
        handler: function (response) {
          alert('Payment successful: ' + response.razorpay_payment_id);
          // Update booking status in backend if needed
        },
      };
      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (error) {
      alert('Error submitting booking. Please try again.');
    } finally {
      setLoading(false);
      setTimeout(() => setSuccessMessage(''), 3000);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50 via-orange-50 to-green-50 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="text-center mb-12">
          <h1 className="text-4xl md:text-5xl font-bold text-amber-900 mb-2">
            🐯 Book Your Safari
          </h1>
          <p className="text-lg text-green-700">Experience the wilderness of Ranthambhore</p>
        </div>

        {/* Success Message */}
        {successMessage && (
          <div className="mb-6 p-4 bg-green-100 border-l-4 border-green-600 text-green-800 rounded-lg">
            {successMessage}
          </div>
        )}

        {/* Form Card */}
        <form onSubmit={handleSubmit} className="bg-white rounded-lg shadow-2xl overflow-hidden">
          {/* Decorative Header */}
          <div className="bg-gradient-to-r from-amber-600 to-orange-600 h-2"></div>

          <div className="p-8 md:p-10">
            {/* Name Input */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Full Name
              </label>
              <input
                type="text"
                name="name"
                value={formData.name}
                onChange={handleChange}
                placeholder="Enter your full name"
                required
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 focus:border-transparent transition"
              />
            </div>

            {/* Email Input */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Email Address
              </label>
              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="your.email@example.com"
                required
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 focus:border-transparent transition"
              />
            </div>

            {/* Date Input */}
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Preferred Date
              </label>
              <input
                type="date"
                name="date"
                value={formData.date}
                onChange={handleChange}
                required
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 focus:border-transparent transition"
              />
            </div>

            {/* Zone Selection */}
            <div className="mb-8">
              <label className="block text-sm font-semibold text-gray-700 mb-2">
                Safari Zone
              </label>
              <select
                name="zone"
                value={formData.zone}
                onChange={handleChange}
                required
                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-amber-500 focus:border-transparent transition appearance-none cursor-pointer"
              >
                <option value="">Choose a zone</option>
                <option value="Zone 1">Zone 1 - Ranthambhore Fort Area</option>
                <option value="Zone 2">Zone 2 - Padam Lake Area</option>
                <option value="Zone 3">Zone 3 - Jogi Mahal Area</option>
                <option value="Zone 4">Zone 4 - Rajbagh Lake Area</option>
                <option value="Zone 5">Zone 5 - Malik Talao Area</option>
              </select>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-gradient-to-r from-amber-600 to-orange-600 hover:from-amber-700 hover:to-orange-700 text-white font-bold py-3 px-6 rounded-lg transition transform hover:scale-105 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg"
            >
              {loading ? 'Processing...' : '🐾 Book Now & Pay'}
            </button>

            {/* Info Box */}
            <div className="mt-8 p-4 bg-green-50 border-l-4 border-green-600 rounded">
              <p className="text-sm text-green-800">
                <span className="font-semibold">📍 Note:</span> Early morning safaris (5:00 AM - 8:00 AM) have the highest tiger sighting probability.
              </p>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default BookingForm;
